// Generates `src/registry.generated.ts` by scanning `src/capabilities/*` for
// folders that export a `capability`. This runs before every dev, build,
// typecheck, and publish (see package.json), so adding a capability means adding
// ONE folder and nothing else: no shared file to edit, so no merge conflicts
// between capability PRs. The generated file is git-ignored on purpose.
import { readdirSync, writeFileSync, existsSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const here = dirname(fileURLToPath(import.meta.url));
const capsDir = join(here, "..", "src", "capabilities");
const outFile = join(here, "..", "src", "registry.generated.ts");

const names = existsSync(capsDir)
  ? readdirSync(capsDir, { withFileTypes: true })
      .filter((d) => d.isDirectory() && existsSync(join(capsDir, d.name, "index.ts")))
      .map((d) => d.name)
      .sort()
  : [];

// Numbered aliases keep this file valid no matter what a folder is named, and it
// is never read by a human, so the aliases don't need to be meaningful.
const imports = names
  .map((name, i) => `import { capability as c${i} } from "./capabilities/${name}";`)
  .join("\n");

const body = `// AUTO-GENERATED by scripts/gen-registry.mjs — do not edit.
// Regenerated from src/capabilities/* before every dev, build, typecheck, and publish.
import type { CapabilityModule } from "./types";
${imports}

export const capabilities: CapabilityModule[] = [${names.map((_, i) => `c${i}`).join(", ")}];
`;

writeFileSync(outFile, body);
console.log(
  `registry: ${names.length} capabilit${names.length === 1 ? "y" : "ies"} (${names.join(", ") || "none"})`,
);
